setup.query:
mutation ProductMetafieldDeleteSetup($metafields: [MetafieldsSetInput!]!) {
  metafieldsSet(metafields: $metafields) {
    metafields {
      id
      namespace
      key
      type
      value
    }
    userErrors {
      field
      message
      code
      elementIndex
    }
  }
}

readAfterSet.query:
query ProductMetafieldDeleteRead($id: ID!) {
  product(id: $id) {
    id
    singularDeleted: metafield(namespace: "custom", key: "singular_delete_me") {
      id
      namespace
      key
      type
      value
    }
    metafields(first: 10, namespace: "custom") {
      nodes {
        id
        namespace
        key
        type
        value
      }
    }
  }
}

delete.query:
mutation ProductMetafieldDeleteById($input: MetafieldDeleteInput!) {
  metafieldDelete(input: $input) {
    deletedId
    userErrors {
      field
      message
    }
  }
}

